class Command(BaseCommand):
    help = 'Carga las consultas de Facundo (Diciembre 2025 - Marzo 2026)'

    def handle(self, *args, **options):
        try:
            facundo = User.objects.get(email='comercial3@supplyargentina.com.ar')
        except User.DoesNotExist:
            self.stderr.write('No existe el usuario comercial3@supplyargentina.com.ar')
            return

        creadas = 0
        for row in DATOS:
            fecha, productos, cantidad, razon_social, contacto, cuit, telefono, email, estado, via, nro_cot, notas = row
            Consulta.objects.create(
                fecha=fecha,
                productos=productos,
                cantidad=cantidad,
                razon_social=razon_social,
                contacto=contacto,
                cuit=cuit,
                telefono=telefono,
                email=email,
                estado=estado,
                via_entrada=via,
                numero_cotizacion=nro_cot,
                notas=notas,
                vendedor=facundo,
            )
            creadas += 1

        self.stdout.write(self.style.SUCCESS(f'{creadas} consultas cargadas para Facundo.'))
